import React, { useEffect, useState, useCallback } from "react";
import api from "../api/api"; // ✅ Usamos nuestra instancia configurada
import { useParams, useNavigate } from "react-router-dom";
import { FaArrowLeft, FaPlus, FaBoxOpen } from "react-icons/fa";

export default function ProductosPorCategoria() {
  const { categoria_id } = useParams();
  const navigate = useNavigate();

  const [productos, setProductos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);

  const [nuevoProducto, setNuevoProducto] = useState({
    nombre: "",
    descripcion: "",
    precio: "",
    stock: "",
    imagen: null,
  });

  // 📄 PAGINACIÓN
  const [paginaActual, setPaginaActual] = useState(1);
  const productosPorPagina = 8;

  const obtenerProductos = useCallback(async () => {
    try {
      setLoading(true);
      // ✅ URL simplificada gracias a la baseURL de 'api'
      const res = await api.get(`/productos/categoria/${categoria_id}`);

      setProductos(
        res.data.map((p) => ({
          _id: p._id, // Mantenemos el estándar de MongoDB
          nombre: p.nombre,
          descripcion: p.descripcion,
          precio: p.precio,
          stock: p.stock,
          imagen: p.imagen,
        }))
      );
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    } finally {
      setLoading(false);
    }
  }, [categoria_id]);

  useEffect(() => {
    obtenerProductos();
  }, [obtenerProductos]);

  const handleChange = (e) => {
    setNuevoProducto({
      ...nuevoProducto,
      [e.target.name]: e.target.value,
    });
  };

  const handleFileChange = (e) => {
    setNuevoProducto({
      ...nuevoProducto,
      imagen: e.target.files[0],
    });
  };
const guardarProducto = async (e) => {
  e.preventDefault();
  try {
    const formData = new FormData();
    // ... otros appends (nombre, precio, etc.)

    if (nuevoProducto.imagen) {
      // ⚠️ ESTA PALABRA DEBE SER "imagen" (en minúsculas) 
      // para que coincida con upload.single("imagen") en tu ruta
      formData.append("imagen", nuevoProducto.imagen); 
    }

    await api.post("/productos", formData, {
      headers: { "Content-Type": "multipart/form-data" },
    });
    
    // ... resto del código

      setShowModal(false);
      setNuevoProducto({ nombre: "", descripcion: "", precio: "", stock: "", imagen: null });
      obtenerProductos(); 
      alert("✨ Producto guardado con éxito");
    } catch (error) {
      console.error("❌ Error al crear producto:", error);
      alert("Error al guardar: " + (error.response?.data?.mensaje || "Verifica tu conexión"));
    }
  };

  // Lógica de paginación
  const totalPaginas = Math.ceil(productos.length / productosPorPagina);
  const inicio = (paginaActual - 1) * productosPorPagina;
  const productosPaginados = productos.slice(inicio, inicio + productosPorPagina);

  if (loading) return (
    <div className="text-center mt-5">
      <div className="spinner-border text-primary"></div>
      <p className="mt-2">Cargando productos...</p>
    </div>
  );

  return (
    <div className="container-fluid p-4">
      {/* Cabecera */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <button className="btn btn-outline-secondary shadow-sm" onClick={() => navigate(-1)}>
          <FaArrowLeft className="me-2" /> Volver
        </button>
        <h4 className="fw-bold mb-0 text-dark">
          <FaBoxOpen className="me-2 text-primary" /> Productos
        </h4>
        <button className="btn btn-success shadow-sm" onClick={() => setShowModal(true)}>
          <FaPlus className="me-2" /> Agregar Producto
        </button>
      </div>

      {/* Grid de Productos */}
      <div className="row g-4">
        {productosPaginados.length === 0 ? (
          <div className="col-12 text-center py-5">
            <p className="text-muted">No hay productos en esta categoría todavía.</p>
          </div>
        ) : (
          productosPaginados.map((p) => (
            <div key={p._id} className="col-xl-3 col-lg-4 col-md-6">
              <div className="card h-100 border-0 shadow-sm transition-all">
                <div style={{ height: "180px" }} className="bg-light position-relative">
                  {p.imagen ? (
                    <img
                      src={`http://localhost:5000/uploads/${p.imagen}`}
                      alt={p.nombre}
                      className="w-100 h-100"
                      style={{ objectFit: "cover" }}
                    />
                  ) : (
                    <div className="h-100 d-flex align-items-center justify-content-center text-muted">
                      Sin imagen
                    </div>
                  )}
                </div>
                <div className="card-body">
                  <h6 className="fw-bold text-dark mb-1">{p.nombre}</h6>
                  <p className="small text-muted mb-3 text-truncate">{p.descripcion}</p>
                  <div className="d-flex justify-content-between align-items-center">
                    <span className="badge bg-primary fs-6">${p.precio}</span>
                    <span className="small text-secondary">Stock: <b>{p.stock}</b></span>
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div className="modal show d-block" style={{ background: "rgba(0,0,0,.6)", backdropFilter: "blur(4px)" }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 shadow-lg">
              <div className="modal-header bg-primary text-white">
                <h5 className="modal-title fw-bold">Nuevo Producto</h5>
                <button type="button" className="btn-close btn-close-white" onClick={() => setShowModal(false)}></button>
              </div>
              <form onSubmit={guardarProducto}>
                <div className="modal-body p-4">
                  <div className="row g-3">
                    <div className="col-12">
                      <label className="form-label fw-bold small">Nombre del Producto</label>
                      <input name="nombre" className="form-control" value={nuevoProducto.nombre} onChange={handleChange} required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small">Precio</label>
                      <input name="precio" type="number" step="0.01" className="form-control" value={nuevoProducto.precio} onChange={handleChange} required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small">Stock</label>
                      <input name="stock" type="number" className="form-control" value={nuevoProducto.stock} onChange={handleChange} required />
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold small">Descripción</label>
                      <textarea name="descripcion" className="form-control" rows="2" value={nuevoProducto.descripcion} onChange={handleChange}></textarea>
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold small">Imagen del Producto</label>
                      <input type="file" accept="image/*" className="form-control" onChange={handleFileChange} />
                    </div>
                  </div>
                </div>
                <div className="modal-footer border-0">
                  <button type="button" className="btn btn-light" onClick={() => setShowModal(false)}>Cancelar</button>
                  <button type="submit" className="btn btn-primary px-4">Guardar</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
